<?php/** * WooCommerce specific functions and definitions * * @package AquaLuxe */if (!defined('ABSPATH')) {    exit; // Exit if accessed directly}/** * WooCommerce setup function. * * @link https://docs.woocommerce.com/document/third-party-custom-theme-compatibility/ * @link https://github.com/woocommerce/woocommerce/wiki/Enabling-product-gallery-features-(zoom,-swipe,-lightbox) * * @return void */function aqualuxe_woocommerce_setup() {    // Add theme support for WooCommerce    add_theme_support('woocommerce');        // Add support for WooCommerce product gallery features    if (aqualuxe_is_product_gallery_zoom_enabled()) {        add_theme_support('wc-product-gallery-zoom');    }        if (aqualuxe_is_product_gallery_lightbox_enabled()) {        add_theme_support('wc-product-gallery-lightbox');    }        if (aqualuxe_is_product_gallery_slider_enabled()) {        add_theme_support('wc-product-gallery-slider');    }}add_action('after_setup_theme', 'aqualuxe_woocommerce_setup');/** * WooCommerce specific scripts & stylesheets. * * @return void */function aqualuxe_woocommerce_scripts() {    // WooCommerce styles are enqueued in assets.php}add_action('wp_enqueue_scripts', 'aqualuxe_woocommerce_scripts');/** * Disable the default WooCommerce stylesheet. * * Removing the default WooCommerce stylesheet and enqueueing your own will * protect you during WooCommerce core updates. * * @link https://docs.woocommerce.com/document/disable-the-default-stylesheet/ */add_filter('woocommerce_enqueue_styles', '__return_empty_array');/** * Add 'woocommerce-active' class to the body tag. * * @param array $classes CSS classes applied to the body tag. * @return array $classes modified to include 'woocommerce-active' class. */function aqualuxe_woocommerce_active_body_class($classes) {    $classes[] = 'woocommerce-active';        return $classes;}add_filter('body_class', 'aqualuxe_woocommerce_active_body_class');/** * Related Products Args. * * @param array $args related products args. * @return array $args related products args. */function aqualuxe_woocommerce_related_products_args($args) {    $defaults = array(        'posts_per_page' => aqualuxe_get_related_products_count(),        'columns'        => aqualuxe_get_product_columns(),    );    $args = wp_parse_args($defaults, $args);    return $args;}add_filter('woocommerce_output_related_products_args', 'aqualuxe_woocommerce_related_products_args');/** * Remove default WooCommerce wrapper. */remove_action('woocommerce_before_main_content', 'woocommerce_output_content_wrapper', 10);remove_action('woocommerce_after_main_content', 'woocommerce_output_content_wrapper_end', 10);/** * Before Content. * Wraps all WooCommerce content in wrappers which match the theme markup. * * @return void */function aqualuxe_woocommerce_wrapper_before() {    ?>    <main id="primary" class="site-main">        <div class="<?php echo esc_attr(aqualuxe_get_container_width()); ?>">            <?php if (aqualuxe_has_sidebar() && aqualuxe_get_shop_sidebar_position() === 'left') : ?>                <div class="flex flex-col md:flex-row">                    <div class="w-full md:w-1/4 md:pr-6">                        <?php get_sidebar('shop'); ?>                    </div>                    <div class="w-full md:w-3/4">            <?php elseif (aqualuxe_has_sidebar() && aqualuxe_get_shop_sidebar_position() === 'right') : ?>                <div class="flex flex-col md:flex-row">                    <div class="w-full md:w-3/4">            <?php endif; ?>    <?php}add_action('woocommerce_before_main_content', 'aqualuxe_woocommerce_wrapper_before');/** * After Content. * Closes the wrapping divs. * * @return void */function aqualuxe_woocommerce_wrapper_after() {    ?>            <?php if (aqualuxe_has_sidebar() && aqualuxe_get_shop_sidebar_position() === 'left') : ?>                    </div>                </div>            <?php elseif (aqualuxe_has_sidebar() && aqualuxe_get_shop_sidebar_position() === 'right') : ?>                    </div>                    <div class="w-full md:w-1/4 md:pl-6">                        <?php get_sidebar('shop'); ?>                    </div>                </div>            <?php endif; ?>        </div>    </main><!-- #main -->    <?php}add_action('woocommerce_after_main_content', 'aqualuxe_woocommerce_wrapper_after');/** * Sample implementation of the WooCommerce Mini Cart. * * You can add the WooCommerce Mini Cart to header.php like so ... * * <?php * if ( function_exists( 'aqualuxe_woocommerce_header_cart' ) ) { *     aqualuxe_woocommerce_header_cart(); * } * ?> *//** * Cart Fragments. * * Ensure cart contents update when products are added to the cart via AJAX. * * @param array $fragments Fragments to refresh via AJAX. * @return array Fragments to refresh via AJAX. */function aqualuxe_woocommerce_cart_link_fragment($fragments) {    ob_start();    aqualuxe_woocommerce_cart_link();    $fragments['a.cart-contents'] = ob_get_clean();    return $fragments;}add_filter('woocommerce_add_to_cart_fragments', 'aqualuxe_woocommerce_cart_link_fragment');/** * Cart Link. * * Displayed a link to the cart including the number of items present and the cart total. * * @return void */function aqualuxe_woocommerce_cart_link() {    ?>    <a class="cart-contents" href="<?php echo esc_url(wc_get_cart_url()); ?>" title="<?php esc_attr_e('View your shopping cart', 'aqualuxe'); ?>">        <span class="cart-contents-count">            <i class="fas fa-shopping-cart" aria-hidden="true"></i>            <span class="count"><?php echo esc_html(WC()->cart->get_cart_contents_count()); ?></span>        </span>        <span class="cart-contents-total"><?php echo wp_kses_data(WC()->cart->get_cart_subtotal()); ?></span>    </a>    <?php}/** * Header Cart. * * @return void */function aqualuxe_woocommerce_header_cart() {    if (is_cart()) {        $class = 'current-menu-item';    } else {        $class = '';    }    ?>    <div id="site-header-cart" class="site-header-cart">        <div class="<?php echo esc_attr($class); ?>">            <?php aqualuxe_woocommerce_cart_link(); ?>        </div>        <div class="site-header-cart-dropdown">            <?php            $instance = array(                'title' => '',            );            the_widget('WC_Widget_Cart', $instance);            ?>        </div>    </div>    <?php}/** * Mini Cart. * * @return void */function aqualuxe_woocommerce_mini_cart() {    ?>    <div class="mini-cart">        <div class="mini-cart-header">            <h3 class="mini-cart-title"><?php esc_html_e('Cart', 'aqualuxe'); ?></h3>            <button class="mini-cart-close">                <span class="screen-reader-text"><?php esc_html_e('Close', 'aqualuxe'); ?></span>                <i class="fas fa-times" aria-hidden="true"></i>            </button>        </div>        <div class="mini-cart-content">            <?php woocommerce_mini_cart(); ?>        </div>    </div>    <?php}/** * Change number of products per page. * * @return int */function aqualuxe_woocommerce_products_per_page() {    return aqualuxe_get_products_per_page();}add_filter('loop_shop_per_page', 'aqualuxe_woocommerce_products_per_page');/** * Change number of columns in product loop. * * @return int */function aqualuxe_woocommerce_loop_columns() {    return aqualuxe_get_product_columns();}add_filter('loop_shop_columns', 'aqualuxe_woocommerce_loop_columns');/** * Add product short description to product loop. */function aqualuxe_woocommerce_after_shop_loop_item_title() {    global $product;        if ($product && $product->get_short_description()) {        echo '<div class="product-short-description">' . wp_kses_post($product->get_short_description()) . '</div>';    }}add_action('woocommerce_after_shop_loop_item_title', 'aqualuxe_woocommerce_after_shop_loop_item_title', 5);/** * Add wishlist button to product loop. */function aqualuxe_woocommerce_after_shop_loop_item() {    if (aqualuxe_is_wishlist_enabled()) {        global $product;                if ($product) {            $product_id = $product->get_id();            $in_wishlist = aqualuxe_is_product_in_wishlist($product_id);            $wishlist_url = aqualuxe_get_wishlist_url();                        echo '<div class="product-wishlist">';            echo '<a href="#" class="add-to-wishlist" data-product-id="' . esc_attr($product_id) . '" data-wishlist-url="' . esc_url($wishlist_url) . '">';            echo '<i class="' . ($in_wishlist ? 'fas' : 'far') . ' fa-heart" aria-hidden="true"></i>';            echo '<span class="screen-reader-text">' . esc_html__('Add to Wishlist', 'aqualuxe') . '</span>';            echo '</a>';            echo '</div>';        }    }}add_action('woocommerce_after_shop_loop_item', 'aqualuxe_woocommerce_after_shop_loop_item', 20);/** * Add quick view button to product loop. */function aqualuxe_woocommerce_before_shop_loop_item() {    if (aqualuxe_is_quick_view_enabled()) {        global $product;                if ($product) {            $product_id = $product->get_id();                        echo '<div class="product-quick-view">';            echo '<a href="#" class="quick-view-button" data-product-id="' . esc_attr($product_id) . '">';            echo '<i class="fas fa-search-plus" aria-hidden="true"></i>';            echo '<span class="screen-reader-text">' . esc_html__('Quick View', 'aqualuxe') . '</span>';            echo '</a>';            echo '</div>';        }    }}add_action('woocommerce_before_shop_loop_item', 'aqualuxe_woocommerce_before_shop_loop_item', 5);/** * Add sale percentage to product loop. */function aqualuxe_woocommerce_show_product_loop_sale_flash() {    global $product;        if ($product && $product->is_on_sale()) {        $percentage = aqualuxe_get_product_sale_percentage($product->get_id());                if ($percentage) {            echo '<span class="onsale">-' . esc_html($percentage) . '</span>';        } else {            echo '<span class="onsale">' . esc_html__('Sale!', 'aqualuxe') . '</span>';        }    }}remove_action('woocommerce_before_shop_loop_item_title', 'woocommerce_show_product_loop_sale_flash', 10);add_action('woocommerce_before_shop_loop_item_title', 'aqualuxe_woocommerce_show_product_loop_sale_flash', 10);/** * Add sale percentage to single product. */function aqualuxe_woocommerce_show_product_sale_flash() {    global $product;        if ($product && $product->is_on_sale()) {        $percentage = aqualuxe_get_product_sale_percentage($product->get_id());                if ($percentage) {            echo '<span class="onsale">-' . esc_html($percentage) . '</span>';        } else {            echo '<span class="onsale">' . esc_html__('Sale!', 'aqualuxe') . '</span>';        }    }}remove_action('woocommerce_before_single_product_summary', 'woocommerce_show_product_sale_flash', 10);add_action('woocommerce_before_single_product_summary', 'aqualuxe_woocommerce_show_product_sale_flash', 10);/** * Add wishlist button to single product. */function aqualuxe_woocommerce_single_product_summary() {    if (aqualuxe_is_wishlist_enabled()) {        global $product;                if ($product) {            $product_id = $product->get_id();            $in_wishlist = aqualuxe_is_product_in_wishlist($product_id);            $wishlist_url = aqualuxe_get_wishlist_url();                        echo '<div class="product-wishlist">';            echo '<a href="#" class="add-to-wishlist" data-product-id="' . esc_attr($product_id) . '" data-wishlist-url="' . esc_url($wishlist_url) . '">';            echo '<i class="' . ($in_wishlist ? 'fas' : 'far') . ' fa-heart" aria-hidden="true"></i>';            echo '<span>' . esc_html__('Add to Wishlist', 'aqualuxe') . '</span>';            echo '</a>';            echo '</div>';        }    }}add_action('woocommerce_single_product_summary', 'aqualuxe_woocommerce_single_product_summary', 35);